mapper.select:
SELECT id, user_id AS userId, dish_id AS dishId, setmeal_id AS setmealId,
dish_flavor AS dishFlavor, name, image, number, amount, create_time AS createTime
FROM shopping_cart
WHERE user_id = #{userId}

    AND dish_id = #{dishId}


    AND setmeal_id = #{setmealId}


    AND dish_flavor = #{dishFlavor}

LIMIT 1

mapper.update:
UPDATE shopping_cart
SET number = #{number}
WHERE id = #{id}

